     1→import type { MittwaldCliToolHandler } from '../../../../types/mittwald/conversation.js';
     2→import { formatToolResponse } from '../../../../utils/format-tool-response.js';
     3→import { invokeCliTool, CliToolError } from '../../../../tools/index.js';
     4→
     5→interface MittwaldAppDependencyListArgs {
     6→  appType?: string;
     7→  appId?: string;
     8→  includeMetadata?: boolean;
     9→}
    10→
    11→type RawSystemSoftware = {
    12→  id?: string;
    13→  name?: string;
    14→  tags?: string[];
    15→  meta?: Record<string, unknown> | null;
    16→};
    17→
    18→type RawInstalledSystemSoftware = {
    19→  systemSoftwareId?: string;
    20→  systemSoftwareVersion?: {
    21→    current?: string;
    22→    desired?: string;
    23→  } | null;
    24→  updatePolicy?: string;
    25→};
    26→
    27→interface AppInstallationDetails {
    28→  id?: string;
    29→  systemSoftware?: RawInstalledSystemSoftware[];
    30→}
    31→
    32→function buildCliArgs(): string[] {
    33→  return ['app', 'dependency', 'list', '--output', 'json'];
    34→}
    35→
    36→function parseSystemSoftwareList(output: string): RawSystemSoftware[] | undefined {
    37→  if (!output) return undefined;
    38→
    39→  try {
    40→    const parsed = JSON.parse(output);
    41→    if (Array.isArray(parsed)) {
    42→      return parsed as RawSystemSoftware[];
    43→    }
    44→
    45→    if (parsed && typeof parsed === 'object' && Array.isArray((parsed as Record<string, unknown>).data)) {
    46→      return (parsed as { data: RawSystemSoftware[] }).data;
    47→    }
    48→  } catch {
    49→    return undefined;
    50→  }
    51→
    52→  return undefined;
    53→}
    54→
    55→function parseAppInstallation(output: string): AppInstallationDetails | undefined {
    56→  if (!output) return undefined;
    57→
    58→  try {
    59→    const parsed = JSON.parse(output) as unknown;
    60→    if (!parsed || typeof parsed !== 'object') return undefined;
    61→
    62→    const container = parsed as Record<string, unknown>;
    63→
    64→    if ('appInstallation' in container && typeof container.appInstallation === 'object' && container.appInstallation !== null) {
    65→      return container.appInstallation as AppInstallationDetails;
    66→    }
    67→
    68→    return parsed as AppInstallationDetails;
    69→  } catch {
    70→    return undefined;
    71→  }
    72→}
    73→
    74→function filterDependenciesByType(items: RawSystemSoftware[], appType?: string): RawSystemSoftware[] {
    75→  if (!appType) return items;
    76→
    77→  const normalized = appType.trim().toLowerCase();
    78→  return items.filter((item) => item.tags?.some((tag) => tag.toLowerCase() === normalized));
    79→}
    80→
    81→function buildInstalledMap(installed?: RawInstalledSystemSoftware[]): Map<string, RawInstalledSystemSoftware> {
    82→  const map = new Map<string, RawInstalledSystemSoftware>();
    83→  if (!installed) return map;
    84→
    85→  for (const entry of installed) {
    86→    if (!entry?.systemSoftwareId) continue;
    87→    map.set(entry.systemSoftwareId, entry);
    88→  }
    89→
    90→  return map;
    91→}
    92→
    93→function formatDependencies(
    94→  items: RawSystemSoftware[],
    95→  installedMap: Map<string, RawInstalledSystemSoftware>,
    96→  includeMetadata: boolean,
    97→) {
    98→  return items.map((item) => {
    99→    const installed = item.id ? installedMap.get(item.id) : undefined;
   100→    const currentVersion = installed?.systemSoftwareVersion?.current;
   101→    const desiredVersion = installed?.systemSoftwareVersion?.desired;
   102→
   103→    const updateAvailable = currentVersion && desiredVersion && currentVersion !== desiredVersion;
   104→
   105→    const base: Record<string, unknown> = {
   106→      id: item.id,
   107→      name: item.name,
   108→      tags: item.tags ?? [],
   109→      currentVersion,
   110→      desiredVersion,
   111→      updatePolicy: installed?.updatePolicy,
   112→      updateAvailable: updateAvailable ?? false,
   113→    };
   114→
   115→    if (!installed) {
   116→      base.updateAvailable = undefined;
   117→    }
   118→
   119→    if (includeMetadata && item.meta && typeof item.meta === 'object') {
   120→      base.meta = item.meta;
   121→    }
   122→
   123→    return base;
   124→  });
   125→}
   126→
   127→function mapListCliError(error: CliToolError): string {
   128→  if (error.stderr?.toLowerCase().includes('unauthorized')) {
   129→    return 'Authentication failed while listing dependencies. Please re-authenticate and try again.';
   130→  }
   131→
   132→  return error.message;
   133→}
   134→
   135→function mapAppGetError(error: CliToolError, appId: string): string {
   136→  const combined = `${error.stdout ?? ''}\n${error.stderr ?? ''}`.toLowerCase();
   137→
   138→  if (combined.includes('not found') && combined.includes('installation')) {
   139→    return `App installation not found. Please verify the installation ID: ${appId}.\nError: ${error.stderr || error.message}`;
   140→  }
   141→
   142→  return error.message;
   143→}
   144→
   145→export const handleAppDependencyListCli: MittwaldCliToolHandler<MittwaldAppDependencyListArgs> = async (args) => {
   146→  const argv = buildCliArgs();
   147→
   148→  try {
   149→    const listResult = await invokeCliTool({
   150→      toolName: 'mittwald_app_dependency_list',
   151→      argv,
   152→      parser: (stdout, raw) => ({ stdout, stderr: raw.stderr }),
   153→    });
   154→
   155→    const stdout = listResult.result.stdout ?? '';
   156→    const parsed = parseSystemSoftwareList(stdout);
   157→
   158→    if (!parsed) {
   159→      return formatToolResponse(
   160→        'success',
   161→        'Dependencies retrieved (raw output)',
   162→        { rawOutput: stdout },
   163→        {
   164→          command: listResult.meta.command,
   165→          durationMs: listResult.meta.durationMs,
   166→        },
   167→      );
   168→    }
   169→
   170→    let installationDetails: AppInstallationDetails | undefined;
   171→
   172→    let enrichmentWarning: string | undefined;
   173→
   174→    if (args.appId) {
   175→      try {
   176→        const appResult = await invokeCliTool({
   177→          toolName: 'mittwald_app_get',
   178→          argv: ['app', 'get', args.appId, '--output', 'json'],
   179→          parser: (stdout) => stdout,
   180→        });
   181→
   182→        installationDetails = parseAppInstallation(appResult.result);
   183→        if (!installationDetails) {
   184→          enrichmentWarning = 'Unable to parse app installation details; dependency enrichment skipped.';
   185→        }
   186→      } catch (error) {
   187→        if (error instanceof CliToolError) {
   188→          const message = mapAppGetError(error, args.appId);
   189→          return formatToolResponse('error', message, {
   190→            exitCode: error.exitCode,
   191→            stderr: error.stderr,
   192→            stdout: error.stdout,
   193→            suggestedAction: error.suggestedAction,
   194→          });
   195→        }
   196→
   197→        return formatToolResponse(
   198→          'error',
   199→          `Failed to fetch app installation details: ${error instanceof Error ? error.message : String(error)}`,
   200→        );
   201→      }
   202→    }
   203→
   204→    const dependencies = filterDependenciesByType(parsed, args.appType);
   205→    const installedMap = buildInstalledMap(installationDetails?.systemSoftware);
   206→    const includeMetadata = Boolean(args.includeMetadata);
   207→
   208→    const formatted = formatDependencies(dependencies, installedMap, includeMetadata);
   209→
   210→    return formatToolResponse(
   211→      'success',
   212→      `Found ${formatted.length} dependenc${formatted.length === 1 ? 'y' : 'ies'}`,
   213→      {
   214→        filters: {
   215→          appType: args.appType,
   216→          appId: args.appId,
   217→        },
   218→        dependencies: formatted,
   219→      },
   220→      {
   221→        command: listResult.meta.command,
   222→        durationMs: listResult.meta.durationMs,
   223→        ...(enrichmentWarning ? { warnings: [enrichmentWarning] } : {}),
   224→      },
   225→    );
   226→  } catch (error) {
   227→    if (error instanceof CliToolError) {
   228→      const message = mapListCliError(error);
   229→      return formatToolResponse('error', message, {
   230→        exitCode: error.exitCode,
   231→        stderr: error.stderr,
   232→        stdout: error.stdout,
   233→        suggestedAction: error.suggestedAction,
   234→      });
   235→    }
   236→
   237→    return formatToolResponse(
   238→      'error',
   239→      `Failed to execute CLI command: ${error instanceof Error ? error.message : String(error)}`,
   240→    );
   241→  }
   242→};
